CREATE TABLE `LeadSavedView` (`id` VARCHAR(191) NOT NULL, `userId` VARCHAR(191) NOT NULL, `name` VARCHAR(100) NOT NULL, `query` LONGTEXT NOT NULL, `columns` LONGTEXT NULL, `isDefault` TINYINT(1) NOT NULL DEFAULT 0, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL, PRIMARY KEY (`id`), UNIQUE INDEX `LeadSavedView_userId_name_key` (`userId`,`name`), INDEX `LeadSavedView_userId_isDefault_idx` (`userId`,`isDefault`), CONSTRAINT `LeadSavedView_userId_fkey` FOREIGN KEY (`userId`) REFERENCES `User`(`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `LeadAssignmentRule` (`id` VARCHAR(191) NOT NULL, `name` VARCHAR(191) NOT NULL, `priority` INTEGER NOT NULL DEFAULT 100, `active` TINYINT(1) NOT NULL DEFAULT 1, `strategy` ENUM('OWNER','ROUND_ROBIN') NOT NULL, `criteria` LONGTEXT NOT NULL, `targetOwnerId` VARCHAR(191) NULL, `organizationUnitId` VARCHAR(191) NULL, `lastAssignedUserId` VARCHAR(191) NULL, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL, PRIMARY KEY (`id`), INDEX `LeadAssignmentRule_active_priority_idx` (`active`,`priority`), INDEX `LeadAssignmentRule_organizationUnitId_active_idx` (`organizationUnitId`,`active`), CONSTRAINT `LeadAssignmentRule_targetOwnerId_fkey` FOREIGN KEY (`targetOwnerId`) REFERENCES `User`(`id`) ON DELETE SET NULL, CONSTRAINT `LeadAssignmentRule_organizationUnitId_fkey` FOREIGN KEY (`organizationUnitId`) REFERENCES `OrganizationUnit`(`id`) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
